// Previous attempt was wrong: it asserted conjuncts of the postcondition's
// HYPOTHESIS (e.g. `post1_netc.my_end_point() == pre_netc.my_end_point()`)
// as if they were unconditional facts. They are not — they live on the LHS
// of the `(...) ==> det_send_packet_equal(...)` ensures and are not in
// `requires`, so Verus correctly rejected them.
//
// The repair: re-state each piece of the hypothesis-H as an *implication*
// (the conjunct of H on the left, a useful consequence on the right). Each
// such implication is a tautology / follows by unfolding the open specs,
// so Verus must verify it — none of them assumes anything on faith. Having
// both runs' facts side-by-side at the top level lets z3 line up the
// disjoint triggers inside `send_log_entry_reflects_packet`,
// `is_marshalable_data`, and the symbolic `pre + seq![..]` history rewrite.

// (1) End-point chain: pre==post1 and pre==post2 forces post1==post2.
assert(post1_netc.my_end_point() == pre_netc.my_end_point()
    && post2_netc.my_end_point() == pre_netc.my_end_point()
    ==> post1_netc.my_end_point() == post2_netc.my_end_point());

// (2) `<==>` is just `==` on bool — surface this for each run so z3
// can equate `post_i.ok()` with `r_i.0` when the hypothesis is in play.
assert((post1_netc.ok() <==> r1.0) ==> (post1_netc.ok() == r1.0));
assert((post2_netc.ok() <==> r2.0) ==> (post2_netc.ok() == r2.0));

// (3) Under r_i.0, the net_event is Some — pull both into scope.
assert((r1.0 ==> r1.1@ is Some) ==> (r1.0 ==> r1.1@ is Some));
assert((r2.0 ==> r2.1@ is Some) ==> (r2.0 ==> r2.1@ is Some));

// (4) `send_log_entry_reflects_packet` is `pub open spec`, so unfolding
// gives us `event is Send` and the abstractify equation. Lift both runs'
// versions to the top level so the trigger on `arrow_Send_s()` fires for
// each event.
assert(r1.0 && (r1.1@ is Some)
    && send_log_entry_reflects_packet(r1.1@.unwrap(), &cpacket)
    ==> (r1.1@.unwrap() is Send)
        && cpacket@ == abstractify_net_packet_to_sht_packet(r1.1@.unwrap().arrow_Send_s()));
assert(r2.0 && (r2.1@ is Some)
    && send_log_entry_reflects_packet(r2.1@.unwrap(), &cpacket)
    ==> (r2.1@.unwrap() is Send)
        && cpacket@ == abstractify_net_packet_to_sht_packet(r2.1@.unwrap().arrow_Send_s()));

// (5) Cross-link: if both runs reflect the same `cpacket`, their
// abstractified packets agree. Tautology by transitivity of `==`.
assert(r1.0 && r2.0 && (r1.1@ is Some) && (r2.1@ is Some)
    && send_log_entry_reflects_packet(r1.1@.unwrap(), &cpacket)
    && send_log_entry_reflects_packet(r2.1@.unwrap(), &cpacket)
    ==> abstractify_net_packet_to_sht_packet(r1.1@.unwrap().arrow_Send_s())
        == abstractify_net_packet_to_sht_packet(r2.1@.unwrap().arrow_Send_s()));

// (6) `is_marshalable_data` (open spec) — lift both runs so z3 can see
// the `sht_demarshal_data(event.arrow_Send_s().msg).is_marshalable()`
// fact under the conditional.
assert(r1.0 && (r1.1@ is Some) && is_marshalable_data(r1.1@.unwrap())
    ==> net_packet_bound(r1.1@.unwrap().arrow_Send_s().msg)
        && sht_demarshal_data(r1.1@.unwrap().arrow_Send_s().msg).is_marshalable());
assert(r2.0 && (r2.1@ is Some) && is_marshalable_data(r2.1@.unwrap())
    ==> net_packet_bound(r2.1@.unwrap().arrow_Send_s().msg)
        && sht_demarshal_data(r2.1@.unwrap().arrow_Send_s().msg).is_marshalable());

// (7) History-extension shape per run (follows from `Seq` `+`).
assert(r1.0 && post1_netc.history() == pre_netc.history() + seq![r1.1@.unwrap()]
    ==> post1_netc.history().len() == pre_netc.history().len() + 1
        && post1_netc.history().last() == r1.1@.unwrap());
assert(r2.0 && post2_netc.history() == pre_netc.history() + seq![r2.1@.unwrap()]
    ==> post2_netc.history().len() == pre_netc.history().len() + 1
        && post2_netc.history().last() == r2.1@.unwrap());
